('8374a4c2-be06-44be-a56e-1f8835efea1f','Sm 42','L 1264',56.8518,14.1612,'tumi × risti : stin : þansi : iftiʀ × asur : ¶ bruþur × sin × þan : aʀ : uaʀ : s^kibari : hrhls : ku¶nuks','"Tumi/"Tummi/"Dómi reisti stein þenna eptir "Ǫzur, bróður sinn, þann er var skipari "Haralds konungs.','Tume/Tumme/Domme reste denna sten efter Assur, sin broder, som var skeppsman åt kung Harald.','Tumi/Tummi/Dómi raised this stone in memory of Ǫzurr, his brother, he who was King Haraldr''s seaman.',NULL,'Inskriften går i två raka rader på stenens ena smalsida.','Runsten','Rödaktig medelkornig gnejs','Småland'),
('ead15fe9-a4bf-4b87-a864-96d3e3c06c88','Sö 38',NULL,58.9448,17.5061,'[…ʀ : raisti : stain : þinsa : at : fraukiʀ : faþur : sin : kuþan : kuþ : hialbi : ant : ha(n)…]','"… ræisti stæin þennsa at "Frøygæiʀ, faður sinn goðan. "Guð hialpi and han[s].','… reste denna sten efter Fröger, sin gode fader. Gud hjälpe hans ande.','… raised this stone in memory of Freygeirr, his good father. May God help his spirit.',NULL,NULL,'Runsten','Sten','Södermanland'),
('c58877f7-fdfe-49bb-aa8d-eaf77135bb4f','Sö 223',NULL,59.0436,17.8074,'[…al… · faþiʀ : at · sun : runa(ʀ) …]','… faðiʀ at sun runaʀ …','… fadern efter sonen runor …','… father in memory of son, runes …',NULL,NULL,'Fragment av runsten','Sten','Södermanland'),
('dfbdd13d-4873-4d9b-a57c-6dbc66bfe698','Sm 152','L 1288',57.3184,15.8534,'…fi · karþ… … [afti × hk]rulf × faþur sin [uk asr ×] uk · ikir','"… gerð[i](?) … eptir "Herjulf(?), fǫður sinn, ok "Ǫzur/"Ásu ok "Ingigerði/"Ingigerðr.','… gjorde … efter Härjulv(?), sin fader, och Assur/Åsa och Ingegerd.','… made(?) … in memory of Herjulfr(?), his father, and (in memory of) Ǫzurr/Ása and Ingigerðr.',NULL,NULL,'Fragment av runsten','Sten','Småland'),
('2d09e5ed-b788-4891-9fba-c75664729cf4','Öl 36','B 1055|B 1079|L 1306|BN 68',56.7109,16.7053,'× (h)[e]rfri[þ- …-] × uiþbiurn × litu × raisa × stain × þina × at × fastulf × faþur sin ×× siklaug × lit × raisa aftiʀ : bunta × sin × han × iaʀ × krafin × i × kirikiu ×','"Hærfrið[r]/"Hærfreð[r] [ok] "Viðbiorn letu ræisa stæin þenna at "Fastulf, faður sinn. "Siglaug let ræisa æftiʀ bonda sinn. Hann iaʀ grafinn i kirkiu.',NULL,'Herfríðr/Herfreðr and Viðbjǫrn had this stone raised in memory of Fastulfr, their father. Siglaug had (it) raised in memory of her husband. He is buried in the church.',NULL,NULL,'Runsten','Grå kalksten','Öland'),
('347486a8-0da4-44fd-9c06-6eceafceee30','G 333',NULL,57.8537,19.0234,'þuea-','…',NULL,'…',NULL,NULL,'Putsinskrift','Kalkputs','Gotland'),
('f013076e-6507-425f-808a-39dffa9f8271','G 200',NULL,57.4799,18.3908,'uni : auk : haknuiþr : arfaʀ : rakna : þaiʀ … …(h)in : aail : ui : ku-… …(ʀ)muþ : hialbi : soul : sunta:lausi : kris-… …t : auþualtr risti r--…','"Uni/"Unni ok "Hagnviðr, arfaʀ "Ragna, þæiʀ … … … … … "[Gæi]ʀmoð(?). Hialpi sial syndalausi "Kris[tr] … "Auðvaldr risti r[uniʀ].','Une (el. Unne) och Hagnvid, Ragnes arvingar, de … (Gair)mod(?). Den syndfrie Kristus hjälpe själen … Audvald ristade runorna.','Uni/Unni and Hagnviðr, Ragni''s heirs, they … Geirmóðr(?). May the sinfree Christ help the soul … Auðvaldr carved the runes.','Ca. 1100',NULL,'Fragment av runsten','Kalksten','Gotland'),
('7b741450-c382-4613-9e55-58ec0cb15610','Sö 125','B 815|L 861',58.8771,17.1741,'[ketilfas × let · reisa ×] tsein × eftiʀ × bryniulf × f[aþur × sin × guþan × hialmbi · i]n heilhi × kristr × h[ans| |sal]','"Ketilfastr lét reisa stein eptir "Brynjulf, fǫður sinn góðan. Hjalpi hinn helgi "Kristr hans sál.','Kättilfast lät resa stenen efter Brynjulv, sin gode fader. Hjälpe den helige Krist hans själ.','Ketilfastr had the stone raised in memory of Brynjulfr, her good father. May the holy Christ help his soul.',NULL,'Har legat som tröskelsten och är därför mycket nött genom trampning.','Runsten','Sten','Södermanland'),
