('1f60eaeb-0e87-484a-8a74-3cc9ec68a41a','Sö 273',NULL,59.1317,18.1917,'+ sikni(u)- + raisti + stai- -t + siʀ^uþr + faþur sin + siba --(o)þur','"Signjó[tr] reisti stei[n a]t "Sigrøð, fǫður sinn, "Sibba [br]óður.','Signjut reste stenen efter Sigröd, sin fader, Sibbes broder.','Signjótr raised the stone in memory of Sigrøðr, his father, Sibbi''s brother.',NULL,NULL,'Runsten','Gråsten','Södermanland'),
('674f14e3-f8a8-4555-bf3e-7fe26416ee13','Sö 9',NULL,59.1092,17.2176,'barkuiþr × auk × þu : helka × raistu × stain × þansi : at · ulf : sun · sin · han × entaþis + miþ : ikuari + kuþ + hialbi + salu ulfs ×','"Bergviðr/"Barkviðr ok þau "Hælga ræistu stæin þannsi at "Ulf, sun sinn. Hann ændaðis með "Ingvari. "Guð hialpi salu "Ulfs.','Bergvid/Barkvid, han och Helga, reste denna sten efter Ulv, sin son. Han ändades med Ingvar. Gud hjälpe Ulvs själ.','Bergviðr/Barkviðr and Helga, they raised this stone in memory of Ulfr, their son. He met his end with Ingvarr. May God help Ulfr''s soul.',NULL,NULL,'Runsten','Sten','Södermanland'),
